template<typename T>
class Register {
    volatile T value;
public:
    Register() = delete;
    Register(const Register&) = delete;
    Register& operator=(const Register&) = delete;

    // 读取操作符
    operator T() const { return value; }

    // 赋值操作符
    T operator=(T v) { value = v; return v; }

    // 位操作
    T operator|=(T v) { value |= v; return value; }
    T operator&=(T v) { value &= v; return value; }
    T operator^=(T v) { value ^= v; return value; }

    // 位设置/清除
    void set_bits(T mask) { value |= mask; }
    void clear_bits(T mask) { value &= ~mask; }
    bool bit_is_set(T bit) const { return (value & bit) != 0; }
};

