// 假设 TIM2, CH1 用于输入捕获
// 请描述配置和 ISR 实现

void TIM2_Config(void) {
    // 配置步骤
}

void TIM2_IRQHandler(void) {
    // 捕获中断处理
}

questions.code_solution:
// 全局变量
static uint32_t last_capture = 0;
static uint32_t overflow_count = 0;
static float measured_freq = 0;

void TIM2_Config(void) {
    // 1. 使能时钟
    RCC->APB1ENR |= RCC_APB1ENR_TIM2EN;

    // 2. 配置 GPIO 为复用功能（AF）
    // GPIOA->MODER, AFR[0] 配置 PA0 为 AF1 (TIM2_CH1)

    // 3. 定时器基本配置
    TIM2->PSC = 71;        // 72MHz / 72 = 1MHz → 1us 分辨率
    TIM2->ARR = 0xFFFFFFFF; // 最大计数范围（32位）

    // 4. 输入捕获配置
    TIM2->CCMR1 |= (0x01 << 0);   // CH1 输入，映射到 TI1
    TIM2->CCER  |= TIM_CCER_CC1E;  // 使能 CH1 捕获
    TIM2->CCER  |= (0x01 << 1);    // 上升沿触发
    TIM2->DIER  |= TIM_DIER_CC1IE | TIM_DIER_UIE; // 捕获中断 + 溢出中断
    TIM2->CR1   |= TIM_CR1_CEN;    // 使能定时器

    // 5. NVIC 配置
    NVIC_EnableIRQ(TIM2_IRQn);
}

void TIM2_IRQHandler(void) {
    // 溢出处理
    if (TIM2->SR & TIM_SR_UIF) {
        TIM2->SR = ~TIM_SR_UIF;
        overflow_count++;
    }

    // 捕获处理
    if (TIM2->SR & TIM_SR_CC1IF) {
        uint32_t current = TIM2->CCR1;

        // 计算两个上升沿之间的时间（处理溢出）
        uint64_t total_ticks = (uint64_t)overflow_count * 0x100000000ULL 
                             + current - last_capture;

        measured_freq = 1000000.0f / total_ticks;  // 1us 分辨率 → Hz

        last_capture = current;
        overflow_count = 0;

        TIM2->SR = ~TIM_SR_CC1IF;
    }
}

questions.code_template:
typedef struct {
    uint8_t *buffer;
    uint32_t size;
    volatile uint32_t head;  // 生产者写入位置
    volatile uint32_t tail;  // 消费者读取位置
} RingBuf;

bool rb_push(RingBuf *rb, uint8_t data) {
    // 请实现
}

bool rb_pop(RingBuf *rb, uint8_t *data) {
    // 请实现
}

questions.code_solution:
typedef struct {
    uint8_t *buffer;
    uint32_t size;
    volatile uint32_t head;
    volatile uint32_t tail;
} RingBuf;

// 满判断：head 的下一个位置是 tail（牺牲一个存储单元）
static inline bool rb_is_full(RingBuf *rb) {
    return ((rb->head + 1) % rb->size) == rb->tail;
}

// 空判断：head == tail
static inline bool rb_is_empty(RingBuf *rb) {
    return rb->head == rb->tail;
}

bool rb_push(RingBuf *rb, uint8_t data) {
    uint32_t next = (rb->head + 1) % rb->size;
    if (next == rb->tail) {
        return false;  // 满
    }
    rb->buffer[rb->head] = data;
    // 内存屏障确保写入在 head 更新之前完成
    __DMB();
    rb->head = next;
    return true;
}

bool rb_pop(RingBuf *rb, uint8_t *data) {
    if (rb->tail == rb->head) {
        return false;  // 空
    }
    *data = rb->buffer[rb->tail];
    __DMB();
    rb->tail = (rb->tail + 1) % rb->size;
    return true;
}

// 获取已存储的数据数量
uint32_t rb_count(RingBuf *rb) {
    return (rb->head - rb->tail + rb->size) % rb->size;
}

questions.explanation:
静态节点池预分配的做法：
```c
#define MAX_NODES 32
static ListNode node_pool[MAX_NODES];
static ListNode *free_list;  // 空闲节点链表

void list_pool_init(void) {
    for (int i = 0; i < MAX_NODES - 1; i++) {
        node_pool[i].next = &node_pool[i+1];
    }
    node_pool[MAX_NODES-1].next = NULL;
    free_list = &node_pool[0];
}

ListNode *alloc_node(void) {
    ListNode *node = free_list;
    if (node) free_list = node->next;
    return node;
}

void free_node(ListNode *node) {
    node->next = free_list;
    free_list = node;
}
```
这种方式内存使用可预测、无碎片、分配/释放 O(1)，非常适合嵌入式系统。

