// 状态、事件枚举
typedef enum { STATE_IDLE, STATE_SHORT_PRESS, STATE_LONG_PRESS } State;
typedef enum { EVENT_PRESS, EVENT_RELEASE, EVENT_TIMEOUT } Event;

// 请实现状态机框架和按键状态转移表

questions.code_solution:
typedef enum { STATE_IDLE, STATE_SHORT_PRESS, STATE_LONG_PRESS } State;
typedef enum { EVENT_PRESS_DOWN, EVENT_PRESS_UP, EVENT_TIMEOUT_1S } Event;

typedef State (*StateHandler)(Event);

// 状态处理函数声明
State idle_handler(Event e);
State short_handler(Event e);
State long_handler(Event e);

// 状态转移表
typedef struct {
    State state;
    StateHandler handler;
    void (*on_enter)(void);
    void (*on_exit)(void);
} StateEntry;

static uint32_t press_start_time = 0;

StateEntry state_table[] = {
    {STATE_IDLE,        idle_handler,  NULL, NULL},
    {STATE_SHORT_PRESS, short_handler, NULL, NULL},
    {STATE_LONG_PRESS,  long_handler, NULL, NULL},
};

static State current_state = STATE_IDLE;

void fsm_dispatch(Event e) {
    State next = state_table[current_state].handler(e);
    if (next != current_state) {
        if (state_table[current_state].on_exit)
            state_table[current_state].on_exit();
        if (state_table[next].on_enter)
            state_table[next].on_enter();
        current_state = next;
    }
}

State idle_handler(Event e) {
    switch (e) {
        case EVENT_PRESS_DOWN:
            press_start_time = get_tick();
            return STATE_SHORT_PRESS;
        default:
            return STATE_IDLE;
    }
}

State short_handler(Event e) {
    switch (e) {
        case EVENT_PRESS_UP:
            toggle_led();   // 短按：切换 LED
            return STATE_IDLE;
        case EVENT_TIMEOUT_1S:
            enter_setting(); // 长按：进入设置
            return STATE_LONG_PRESS;
        default:
            return STATE_SHORT_PRESS;
    }
}

State long_handler(Event e) {
    switch (e) {
        case EVENT_PRESS_UP:
            return STATE_IDLE;
        default:
            return STATE_LONG_PRESS;
    }
}

questions.explanation:
**CRC 系列对比**：

| 类型 | 校验值位宽 | 典型多项式 | 检错能力 | 典型应用 |
|------|-----------|-----------|---------|---------|
| CRC-8 | 8 位 | x⁸+x²+x+1 | 99.6% | 1-Wire, SMBus PEC |
| CRC-16 | 16 位 | x¹⁶+x¹⁵+x²+1 (CRC-16-IBM) | 99.998% | Modbus, USB |
| CRC-32 | 32 位 | x³²+x²⁶+...+1 | 99.99999998% | Ethernet, PNG, GZIP |

**Modbus RTU 使用 CRC-16-IBM**，多项式 0x8005，初始值 0xFFFF，结果异或 0x0000，先传低字节。

**优化技巧**：查表法比逐位计算快 8 倍以上。
```c
// 查表法 CRC-8
uint8_t crc8_table[256];  // 预计算
uint8_t crc8(uint8_t *data, uint32_t len) {
    uint8_t crc = 0x00;
    while (len--) crc = crc8_table[crc ^ *data++];
    return crc;
}
```

questions.answer:
**P、I、D 三项作用**：

| 项 | 作用 | 效果 | 副作用 |
|----|------|------|--------|
| P（比例）| 根据当前误差调整输出 | 响应最快，减小稳态误差 | 过大导致振荡，不能完全消除稳态误差 |
| I（积分）| 累积历史误差 | 消除稳态误差（offset） | 可能引起超调、积分饱和、响应变慢 |
| D（微分）| 预判未来误差趋势 | 减小超调，加快响应 | 放大高频噪声，可能导致输出振荡 |

**积分饱和（Integral Windup）处理**：
```c
// 条件积分 + 输出限幅
integral += error * dt;
// 反计算钳位（Clamping）
if (output > OUT_MAX) {
    output = OUT_MAX;
    integral -= error * dt;  // 回退积分项（反计算）
} else if (output < OUT_MIN) {
    output = OUT_MIN;
    integral -= error * dt;
}
// 或使用积分分离：误差大时不积分，误差小时再启用积分
```

**微分噪声处理**：
```c
// 低通滤波微分项
derivative = (1 - alpha) * derivative + alpha * (error - prev_error) / dt;
// 或用"对测量值微分"而非"对误差微分"，避免设定值阶跃时的微分冲击
// derivative_on_measurement = (prev_measurement - measurement) / dt
```

questions.code_template:
#define FILTER_WINDOW 8

uint16_t adc_filter(uint16_t new_sample) {
    // 请实现滑动窗口滤波
}

questions.code_solution:
#define FILTER_WINDOW 8

typedef struct {
    uint16_t buffer[FILTER_WINDOW];
    uint32_t sum;
    uint8_t  index;
    uint8_t  count;  // 已填充的样本数
} MovingAvgFilter;

static MovingAvgFilter adc_filt = {0};

uint16_t adc_filter(uint16_t new_sample) {
    // 如果窗口已满，减去即将被覆盖的旧值
    if (adc_filt.count >= FILTER_WINDOW) {
        adc_filt.sum -= adc_filt.buffer[adc_filt.index];
    } else {
        adc_filt.count++;
    }

    // 存入新值，更新总和
    adc_filt.buffer[adc_filt.index] = new_sample;
    adc_filt.sum += new_sample;

    // 移动索引
    adc_filt.index = (adc_filt.index + 1) % FILTER_WINDOW;

    // 返回平均值
    return (uint16_t)(adc_filt.sum / adc_filt.count);
}

// 指数移动平均（EMA）版本 —— 更省内存
uint16_t adc_filter_ema(uint16_t new_sample) {
    static uint16_t filtered = 0;
    static bool first = true;

    if (first) {
        filtered = new_sample;
        first = false;
    } else {
        // alpha = 0.125 (1/8), 新的占 1/8, 旧的占 7/8
        filtered = filtered + ((int16_t)(new_sample - filtered) >> 3);
    }
    return filtered;
}

questions.answer:
**HardFault 排查步骤**：

1. **确认故障类型**：读取 CFSR（地址 0xE000ED28）
   - `CFSR[7:0]` = MFSR（MemManage Fault）：非对齐访问、MPU 违规、访问无效地址
   - `CFSR[15:8]` = BFSR（Bus Fault）：总线错误（如访问未启用的外设）
   - `CFSR[31:16]` = UFSR（Usage Fault）：未定义指令、除零、非对齐（关闭时）、协处理器访问

2. **获取故障地址**：
   - MMFAR（0xE000ED34）：触发 MemManage Fault 的地址
   - BFAR（0xE000ED38）：触发 Bus Fault 的地址

3. **从栈帧获取故障时的 PC 和 LR**：
   ```c
   void HardFault_Handler_C(uint32_t *hardfault_args) {
       uint32_t stacked_r0  = hardfault_args[0];
       uint32_t stacked_r1  = hardfault_args[1];
       uint32_t stacked_r2  = hardfault_args[2];
       uint32_t stacked_r3  = hardfault_args[3];
       uint32_t stacked_r12 = hardfault_args[4];
       uint32_t stacked_lr  = hardfault_args[5];  // 故障时的返回地址
       uint32_t stacked_pc  = hardfault_args[6];  // 故障时的程序计数器
       uint32_t stacked_psr = hardfault_args[7];

       printf("Fault at PC: 0x%08X, LR: 0x%08X\n", stacked_pc, stacked_lr);
       // 用 addr2line 或反汇编窗口定位源代码行
   }

   __attribute__((naked))
   void HardFault_Handler(void) {
       __asm volatile(
           "TST LR, #4\n"        // 检查 EXC_RETURN bit2 确定 MSP/PSP
           "ITE EQ\n"
           "MRSEQ R0, MSP\n"
           "MRSNE R0, PSP\n"
           "B HardFault_Handler_C\n"
       );
   }
   ```

4. **常见故障原因检查清单**：
   - 栈溢出（数组越界、递归过深）→ 检查栈 watermark
   - 访问 NULL / 野指针 → PC 在异常地址
   - 外设时钟未使能就访问其寄存器 → BFAR 指向外设地址
   - 非对齐访问 → CFSR 的 MFSR 位被置

**栈溢出检测方案**：

**1. 栈水印（Stack Watermark/Pattern Fill）**：
```c
// 启动时用固定模式填充栈
#define STACK_FILL_PATTERN 0xDEADBEEF
void stack_fill(void) {
    extern uint32_t _estack;  // 栈顶（链接脚本定义）
    extern uint32_t __StackLimit;  // 栈底
    uint32_t *p = &__StackLimit;
    while (p < &_estack) *p++ = STACK_FILL_PATTERN;
}

// 定期检查水印
uint32_t stack_remaining(void) {
    extern uint32_t __StackLimit;
    uint32_t *p = &__StackLimit;
    uint32_t remaining = 0;
    while (*p == STACK_FILL_PATTERN && p < &_estack) {
        p++; remaining++;
    }
    return remaining * 4;  // 剩余字节数
}
```
优点：实现简单、零运行时开销（仅检查时有）
缺点：不能实时检测，只能事后查看高水印

**2. MPU 栈保护**（Cortex-M3+）：
- 用 MPU 在栈底设置保护区（Guard Region）
- 栈溢出到保护区时触发 MemManage Fault
- 优点：实时检测、硬件级保护
- FreeRTOS 中 `configCHECK_FOR_STACK_OVERFLOW = 2` 配合使用

**3. 编译器栈分析**：
- `-fstack-usage` 编译选项生成每个函数的栈使用报告
- 静态分析工具（如 StackAnalyzer）
- 优点：编译时检测
- 缺点：不能处理递归和函数指针间接调用

