    STATE_HEADER,
    STATE_LENGTH,
    STATE_PAYLOAD,
    STATE_CHECKSUM
} ParserState;

// 请实现完整的解析器

questions.code_solution:
typedef enum {
    STATE_WAIT_HEAD1,
    STATE_WAIT_HEAD2,
    STATE_LENGTH,
    STATE_PAYLOAD,
    STATE_CHECKSUM,
    STATE_ESCAPE
} ParserState;

typedef struct {
    ParserState state;
    uint8_t buf[256];
    uint8_t length;
    uint8_t index;
    uint8_t checksum;
    bool    escape_next;
} ProtoParser;

void parser_init(ProtoParser *p) {
    p->state = STATE_WAIT_HEAD1;
    p->index = 0;
    p->escape_next = false;
}

typedef enum {
    PARSE_INCOMPLETE = 0,
    PARSE_OK = 1,
    PARSE_CHECKSUM_ERR = -1,
    PARSE_LENGTH_ERR = -2
} ParseResult;

ParseResult parser_feed(ProtoParser *p, uint8_t byte, 
                         uint8_t **payload, uint8_t *payload_len) {
    // 转义处理（最高优先级）
    if (byte == 0xAA && !p->escape_next && p->state != STATE_WAIT_HEAD1) {
        p->escape_next = true;
        return PARSE_INCOMPLETE;
    }

    if (p->escape_next) {
        p->escape_next = false;
        if (byte != 0x00 && byte != 0xAA) {
            goto reset;  // 非法转义序列，重置
        }
        // 否则 byte 继续正常处理（0xAA 或 0x00）
    }

    switch (p->state) {
    case STATE_WAIT_HEAD1:
        if (byte == 0xAA) {
            p->state = STATE_WAIT_HEAD2;
        }
        return PARSE_INCOMPLETE;

    case STATE_WAIT_HEAD2:
        if (byte == 0x55) {
            p->state = STATE_LENGTH;
        } else {
            p->state = STATE_WAIT_HEAD1;
        }
        return PARSE_INCOMPLETE;

    case STATE_LENGTH:
        p->length = byte;
        p->checksum = byte;  // 校验和包含长度字节
        p->index = 0;
        if (p->length > 255) goto reset;
        p->state = (p->length > 0) ? STATE_PAYLOAD : STATE_CHECKSUM;
        return PARSE_INCOMPLETE;

    case STATE_PAYLOAD:
        p->buf[p->index++] = byte;
        p->checksum ^= byte;
        if (p->index >= p->length) {
            p->state = STATE_CHECKSUM;
        }
        return PARSE_INCOMPLETE;

    case STATE_CHECKSUM:
        p->state = STATE_WAIT_HEAD1;
        if (byte == p->checksum) {
            *payload = p->buf;
            *payload_len = p->length;
            return PARSE_OK;
        }
        return PARSE_CHECKSUM_ERR;
    }

reset:
    p->state = STATE_WAIT_HEAD1;
    p->escape_next = false;
    return PARSE_INCOMPLETE;
}

